reorder_and_bind
Alphabetizes columns in each dataframe, then row-binds all into one.


Code
reorder_and_bind &lt;- function(data_list) {
  data_list_reordered &lt;- lapply(data_list, function(df) {
    df %&gt;% dplyr::select(order(colnames(df)))
  })
  combined_df &lt;- do.call(rbind, data_list_reordered)
  return(combined_df)
}

estimate_creatinine
Estimates serum creatinine from a target eGFR using inverse CKD-EPI 2021 equation (numerical optimization). Scalar function, use with mapply().


Code
estimate_creatinine &lt;- function(egfr, age, sex) {
  if (sex == 1) { A &lt;- 0.9; sex_factor &lt;- 1
  } else {        A &lt;- 0.7; sex_factor &lt;- 1.012 }

  estimated_creatinine &lt;- function(Scr) {
    B &lt;- ifelse(Scr &lt;= A, ifelse(sex == 1, -0.302, -0.241), -1.2)
    calculated_egfr &lt;- 142 * (Scr / A)^B * (0.9938^age) * sex_factor
    return((calculated_egfr - egfr)^2)
  }
  result &lt;- optimize(estimated_creatinine, interval = c(0.1, 2.5))
  return(result$minimum)
}

qc_check
Identifies missing data per patient and determines terlipressin discontinuation day.


Code
qc_check &lt;- function(data) {
  id &lt;- character(); checking &lt;- character(); discont_day &lt;- numeric()
  dc_available_cols &lt;- c("dc_available_albumin___999", "dc_available_inr___999",
    "dc_available_scr___999", "dc_available_sna___999", "dc_available_tbili___999")
  dc_cols &lt;- c("dc_albumin", "dc_inr", "dc_scr", "dc_sna", "dc_tbili")
  discont_cols &lt;- grep("^discont_terli_day", names(data), value = TRUE)
  scr_cols &lt;- grep("^scr_terli_day", names(data), value = TRUE)
  other_cols &lt;- setdiff(names(data),
    c("subjectid", discont_cols, scr_cols, dc_available_cols, dc_cols,
      "dc_death_90days", "days_to_discharge", "dc_days_lastencounter",
      "dc_days_to_death", "days_to_lost_to_followup",
      "scr_day1_post_terli", "scr_day2_post_terli", "scr_day3_post_terli",
      "peakhospit_scr", "rrt", "dc_lt_90days", "dc_hd_status", "dc_scr90_value", "dc_terli_use"))

  for (i in seq_len(nrow(data))) {
    current_id &lt;- data$subjectid[i]
    discont_values &lt;- data[i, discont_cols, drop = FALSE]
    scr_values &lt;- data[i, scr_cols, drop = FALSE]
    other_values &lt;- data[i, other_cols, drop = FALSE]
    current_checking &lt;- character(); current_discont_day &lt;- NA

    # 1) Find discontinuation day
    for (j in seq_along(discont_values)) {
      if (!is.na(discont_values[[j]]) && discont_values[[j]] == 1) {
        current_discont_day &lt;- as.numeric(gsub("discont_terli_day", "", names(discont_values)[j]))
        break
      } else if (is.na(discont_values[[j]])) {
        current_checking &lt;- c(current_checking, names(discont_values)[j])
      }
    }

    # 2) Check SCr up to discontinuation day
    if (!is.na(current_discont_day)) {
      cols_to_check &lt;- seq_len(min(current_discont_day + 1, ncol(scr_values)))
      for (k in cols_to_check) {
        if (is.na(scr_values[[k]])) current_checking &lt;- c(current_checking, names(scr_values)[k])
      }
    } else {
      for (k in seq_along(scr_values)) {
        if (is.na(scr_values[[k]])) current_checking &lt;- c(current_checking, names(scr_values)[k])
      }
    }

    # 3) Check DC availability columns
    for (m in seq_along(dc_available_cols)) {
      avail_val &lt;- data[[dc_available_cols[m]]][i]
      if (is.na(avail_val)) {
        current_checking &lt;- c(current_checking, dc_available_cols[m], dc_cols[m]); next
      }
      if (avail_val == 0 && is.na(data[[dc_cols[m]]][i])) {
        current_checking &lt;- c(current_checking, dc_cols[m])
      }
    }

    # 4) Check other variables
    for (l in seq_along(other_values)) {
      if (is.na(other_values[[l]])) current_checking &lt;- c(current_checking, names(other_values)[l])
    }

    # 5) Check dc_death_90days logic
    dc_death_val &lt;- data[["dc_death_90days"]][i]
    days_discharge_val &lt;- data[["days_to_discharge"]][i]
    if (is.na(dc_death_val) || is.na(days_discharge_val)) {
      current_checking &lt;- c(current_checking, "dc_death_90days", "days_to_discharge",
        "dc_days_lastencounter", "dc_days_to_death", "days_to_lost_to_followup")
    } else {
      if (dc_death_val == 0 && is.na(data[["dc_days_lastencounter"]][i]))
        current_checking &lt;- c(current_checking, "dc_days_lastencounter")
      if (dc_death_val == 1 && is.na(data[["dc_days_to_death"]][i]))
        current_checking &lt;- c(current_checking, "dc_days_to_death")
      if (dc_death_val == 2 && is.na(data[["days_to_lost_to_followup"]][i]))
        current_checking &lt;- c(current_checking, "days_to_lost_to_followup")
    }

    if (length(current_checking) &gt; 0 || !is.na(current_discont_day)) {
      id &lt;- c(id, current_id)
      checking &lt;- c(checking, paste(current_checking, collapse = ", "))
      discont_day &lt;- c(discont_day, current_discont_day)
    }
  }
  return(data.frame(subjectid = id, Checking = checking, Discont_Day = discont_day, stringsAsFactors = FALSE))
}

create_dosechange_day
Finds first day (2–13) a dose change occurred.


Code
create_dosechange_day &lt;- function(df) {
  df$dosechange_day &lt;- apply(df, 1, function(row) {
    for (i in 2:13) {
      varname &lt;- paste0("dosechange_terli_day", i)
      if (!is.na(row[[varname]]) && row[[varname]] == 1) return(i)
    }
    return(NA)
  })
  return(df)
}
